/* =========================================================================
   MONITOR THRESHOLDS — LIMITES DE CONTROLE POR CULTURA (seed do CSV Farmbox)
   Fonte: exportacao 'estagios_ativos' (autoritativa; tem as 4 categorias +
   Inimigos Naturais + Pousio, ausentes no raw). Por (cultura, alvo, estagio):
   Controle/Dano Vegetativo + Reprodutivo + tipo de calculo + qtd max/amostra.
   Idempotente (rebuild total do seed 'farmbox'; preserva source='app').
   ATENCAO: aplicar com  sqlcmd -f 65001 -I  (le o arquivo como UTF-8 + quoted
   identifiers). Sem -f 65001 os nomes acentuados de cultura/alvo corrompem e
   nao casam por nome (perde-se ~metade das culturas + cria alvos duplicados).
   ========================================================================= */
SET QUOTED_IDENTIFIER ON; SET ANSI_NULLS ON; SET NOCOUNT ON; SET XACT_ABORT ON;
GO
-- categoria do alvo em FARM_PEST
IF COL_LENGTH('dbo.FARM_PEST','category') IS NULL ALTER TABLE dbo.FARM_PEST ADD category VARCHAR(20) NULL;
GO
-- niveis reprodutivos + qtd max por amostra em FARM_PEST_THRESHOLD (veg = action_level/damage_level)
IF COL_LENGTH('dbo.FARM_PEST_THRESHOLD','rep_action_level') IS NULL ALTER TABLE dbo.FARM_PEST_THRESHOLD ADD rep_action_level DECIMAL(10,3) NULL;
IF COL_LENGTH('dbo.FARM_PEST_THRESHOLD','rep_damage_level') IS NULL ALTER TABLE dbo.FARM_PEST_THRESHOLD ADD rep_damage_level DECIMAL(10,3) NULL;
IF COL_LENGTH('dbo.FARM_PEST_THRESHOLD','max_per_sample') IS NULL ALTER TABLE dbo.FARM_PEST_THRESHOLD ADD max_per_sample DECIMAL(10,3) NULL;
GO
BEGIN TRAN;
CREATE TABLE #csv (culture_name NVARCHAR(80), cat VARCHAR(20), target_name NVARCHAR(200), stage NVARCHAR(120), veg_ctrl DECIMAL(10,3), veg_dano DECIMAL(10,3), rep_ctrl DECIMAL(10,3), rep_dano DECIMAL(10,3), calc NVARCHAR(60), maxs DECIMAL(10,3));
-- 'Pre Plantio/Pos Colheita' = Pousio
UPDATE #csv SET culture_name = 'Pousio' WHERE culture_name = N'Pré Plantio/Pós Colheita';
-- cria alvos faltantes (por nome normalizado) com categoria
SELECT MIN(c.target_name), MIN(c.cat) FROM #csv c
WHERE NOT EXISTS (SELECT 1 FROM dbo.FARM_PEST pe WHERE LOWER(LTRIM(RTRIM(pe.name))) = LOWER(LTRIM(RTRIM(c.target_name))) COLLATE Latin1_General_CI_AI AND pe.deleted_at IS NULL)
GROUP BY LOWER(LTRIM(RTRIM(c.target_name)));
-- categoria nos alvos existentes
UPDATE pe SET pe.category = x.cat
FROM dbo.FARM_PEST pe
JOIN (SELECT LOWER(LTRIM(RTRIM(target_name))) nm, MIN(cat) cat FROM #csv GROUP BY LOWER(LTRIM(RTRIM(target_name)))) x
  ON LOWER(LTRIM(RTRIM(pe.name))) = x.nm COLLATE Latin1_General_CI_AI
WHERE pe.deleted_at IS NULL AND (pe.category IS NULL OR pe.category <> x.cat);
-- calc -> value_type
-- rebuild do seed: remove tudo que NAO foi editado pelo agronomo (source<>'app')
DELETE FROM dbo.FARM_PEST_THRESHOLD WHERE source <> 'app';
SELECT j.pest_id, j.culture_id, j.stage, 'all', MAX(j.veg_ctrl), MAX(j.veg_dano), MAX(j.rep_ctrl), MAX(j.rep_dano), MAX(j.vt), MAX(j.maxs), 'farmbox'
FROM (
  SELECT pe.id AS pest_id, cu.id AS culture_id, s.stage, s.veg_ctrl, s.veg_dano, s.rep_ctrl, s.rep_dano,
         CASE s.calc WHEN N'Média das Quantidades' THEN 'average_type' WHEN N'Porcentagem de Infestação' THEN 'percentage_type' WHEN N'Presença ou Ausência' THEN 'presence_type' ELSE NULL END AS vt,
         s.maxs
  FROM (
    SELECT c.culture_name, c.target_name, c.stage, MAX(c.veg_ctrl) veg_ctrl, MAX(c.veg_dano) veg_dano,
           MAX(c.rep_ctrl) rep_ctrl, MAX(c.rep_dano) rep_dano, MAX(c.calc) calc, MAX(c.maxs) maxs
    FROM #csv c GROUP BY c.culture_name, c.target_name, c.stage
  ) s
  JOIN dbo.FARM_CULTURE cu ON cu.name = s.culture_name COLLATE Latin1_General_CI_AI AND cu.deleted_at IS NULL
  JOIN dbo.FARM_PEST pe ON LOWER(LTRIM(RTRIM(pe.name))) = LOWER(LTRIM(RTRIM(s.target_name))) COLLATE Latin1_General_CI_AI AND pe.deleted_at IS NULL
) j
-- nao sobrescreve chave (pest,param,phase,culture) editada pelo agronomo; ignora deleted_at DE
-- PROPOSITO: um limite que o agronomo APAGOU (tombstone source='app') NAO deve ser ressuscitado.
WHERE NOT EXISTS (SELECT 1 FROM dbo.FARM_PEST_THRESHOLD t WHERE t.pest_id=j.pest_id AND t.culture_id=j.culture_id AND t.param_name=j.stage AND t.phase='all')
GROUP BY j.pest_id, j.culture_id, j.stage;
COMMIT;
GO
SELECT 'FARM_PEST c/ categoria' t, COUNT(*) n FROM dbo.FARM_PEST WHERE category IS NOT NULL AND deleted_at IS NULL
UNION ALL SELECT 'FARM_PEST_THRESHOLD total', COUNT(*) FROM dbo.FARM_PEST_THRESHOLD WHERE deleted_at IS NULL
UNION ALL SELECT 'THRESHOLD c/ culture', COUNT(*) FROM dbo.FARM_PEST_THRESHOLD WHERE culture_id IS NOT NULL AND deleted_at IS NULL
UNION ALL SELECT 'culturas distintas', COUNT(DISTINCT culture_id) FROM dbo.FARM_PEST_THRESHOLD WHERE deleted_at IS NULL;
GO